# Let me build the "cleaned" grid (removing diagonal-only pixels) and find segments

def clean_grid(grid, color):
    """Remove diagonal-only pixels (has 8-conn but no 4-conn same-color neighbor)"""
    import copy
    H, W = len(grid), len(grid[0])
    cleaned = copy.deepcopy(grid)
    bg = 1 - color if color in [0,1] else 0  # hack for background

    # Find background color (most common)
    from collections import Counter
    flat = [grid[r][c] for r in range(H) for c in range(W)]
    bg = Counter(flat).most_common(1)[0][0]

    for r in range(H):
        for c in range(W):
            if grid[r][c] != color:
                continue
            has_4conn = any(
                0<=r+dr<H and 0<=c+dc<W and grid[r+dr][c+dc]==color
                for dr,dc in [(-1,0),(1,0),(0,-1),(0,1)]
            )
            has_8conn = any(
                0<=r+dr<H and 0<=c+dc<W and grid[r+dr][c+dc]==color
                for dr in [-1,0,1] for dc in [-1,0,1] if (dr,dc)!=(0,0)
            )
            if has_8conn and not has_4conn:
                cleaned[r][c] = bg
    return cleaned

def find_segments(grid, color):
    """Find horizontal and vertical segments of colored pixels"""
    H, W = len(grid), len(grid[0])
    h_segs = []  # (row, start_col, end_col)
    v_segs = []  # (col, start_row, end_row)

    for r in range(H):
        start = None
        for c in range(W):
            if grid[r][c] == color:
                if start is None:
                    start = c
            else:
                if start is not None:
                    if c - start >= 2:
                        h_segs.append((r, start, c-1))
                    start = None
        if start is not None and W - start >= 2:
            h_segs.append((r, start, W-1))

    for c in range(W):
        start = None
        for r in range(H):
            if grid[r][c] == color:
                if start is None:
                    start = r
            else:
                if start is not None:
                    if r - start >= 2:
                        v_segs.append((c, start, r-1))
                    start = None
        if start is not None and H - start >= 2:
            v_segs.append((c, start, H-1))

    return h_segs, v_segs

