# Now find pairs of collinear segments with gaps, and check if removed diags are adjacent

def find_gaps_to_fill(h_segs, v_segs, removed_diags):
    """Find gaps between collinear segments that should be filled"""
    fills = []

    # Horizontal: same row, gap between end of one and start of next
    from collections import defaultdict
    row_segs = defaultdict(list)
    for r, s, e in h_segs:
        row_segs[r].append((s, e))

    for r, segs in row_segs.items():
        segs.sort()
        for i in range(len(segs)-1):
            _, end1 = segs[i]
            start2, _ = segs[i+1]
            gap_start = end1 + 1
            gap_end = start2 - 1
            if gap_start > gap_end:
                continue
            # Check if any removed diag is 8-adjacent to the gap endpoints on this row
            endpoint_left = (r, end1)  # right end of left segment
            endpoint_right = (r, start2)  # left end of right segment

            # Check 8-adjacency of any removed diag to these endpoints
            should_fill = False
            for dr in [-1,0,1]:
                for dc in [-1,0,1]:
                    if (dr,dc)==(0,0): continue
                    if (endpoint_left[0]+dr, endpoint_left[1]+dc) in removed_diags:
                        should_fill = True
                    if (endpoint_right[0]+dr, endpoint_right[1]+dc) in removed_diags:
                        should_fill = True
            if should_fill:
                fills.append(('h', r, gap_start, gap_end))

    # Vertical: same col, gap between end of one and start of next
    col_segs = defaultdict(list)
    for c, s, e in v_segs:
        col_segs[c].append((s, e))

    for c, segs in col_segs.items():
        segs.sort()
        for i in range(len(segs)-1):
            _, end1 = segs[i]
            start2, _ = segs[i+1]
            gap_start = end1 + 1
            gap_end = start2 - 1
            if gap_start > gap_end:
                continue
            endpoint_top = (end1, c)
            endpoint_bottom = (start2, c)

            should_fill = False
            for dr in [-1,0,1]:
                for dc in [-1,0,1]:
                    if (dr,dc)==(0,0): continue
                    if (endpoint_top[0]+dr, endpoint_top[1]+dc) in removed_diags:
                        should_fill = True
                    if (endpoint_bottom[0]+dr, endpoint_bottom[1]+dc) in removed_diags:
                        should_fill = True
            if should_fill:
                fills.append(('v', c, gap_start, gap_end))

    return fills

