    for c in range(W):
        start = None
        for r in range(H):
            if cleaned[r][c] == color:
                if start is None: start = r
            else:
                if start is not None:
                    v_segs.append((c, start, r-1))
                    start = None
        if start is not None:
            v_segs.append((c, start, H-1))

    # Step 3: Find gaps between collinear segments that have diagonal bridges
    output = copy.deepcopy(cleaned)

    row_segs = defaultdict(list)
    for r, s, e in h_segs:
