    """Remove diagonal-only pixels (has 8-conn but no 4-conn same-color neighbor)"""
    import copy
    H, W = len(grid), len(grid[0])
    cleaned = copy.deepcopy(grid)
    bg = 1 - color if color in [0,1] else 0  # hack for background

    # Find background color (most common)
    from collections import Counter
    flat = [grid[r][c] for r in range(H) for c in range(W)]
    bg = Counter(flat).most_common(1)[0][0]

    for r in range(H):
        for c in range(W):
