    return cleaned

def find_segments(grid, color):
    """Find horizontal and vertical segments of colored pixels"""
    H, W = len(grid), len(grid[0])
    h_segs = []  # (row, start_col, end_col)
    v_segs = []  # (col, start_row, end_row)

    for r in range(H):
        start = None
        for c in range(W):
            if grid[r][c] == color:
                if start is None:
                    start = c
            else:
                if start is not None:
                    if c - start >= 2:
                        h_segs.append((r, start, c-1))
                    start = None
        if start is not None and W - start >= 2:
            h_segs.append((r, start, W-1))

