                    start = r
            else:
                if start is not None:
                    v_segs.append((c, start, r-1))
                    start = None
        if start is not None:
            v_segs.append((c, start, H-1))

    # Step 3: Fill gaps using ray-casting
    output = copy.deepcopy(cleaned)

    # Horizontal gaps
    row_segs = defaultdict(list)
    for r, s, e in h_segs:
        row_segs[r].append((s, e))

    for r, segs in row_segs.items():
        segs.sort()
        for i in range(len(segs)-1):
            _, end1 = segs[i]
            start2, _ = segs[i+1]
            gap_size = start2 - end1 - 1
            if gap_size <= 0 or gap_size > MAX_GAP:
                continue
            should_fill = False
            for d in range(1, MAX_RAY + 1):
