    H, W = len(grid), len(grid[0])
    cleaned = copy.deepcopy(grid)
    bg = 1 - color if color in [0,1] else 0  # hack for background

    # Find background color (most common)
    from collections import Counter
    flat = [grid[r][c] for r in range(H) for c in range(W)]
    bg = Counter(flat).most_common(1)[0][0]

    for r in range(H):
        for c in range(W):
            if grid[r][c] != color:
                continue
            has_4conn = any(
                0<=r+dr<H and 0<=c+dc<W and grid[r+dr][c+dc]==color
                for dr,dc in [(-1,0),(1,0),(0,-1),(0,1)]
            )
            has_8conn = any(
                0<=r+dr<H and 0<=c+dc<W and grid[r+dr][c+dc]==color
                for dr in [-1,0,1] for dc in [-1,0,1] if (dr,dc)!=(0,0)
            )
            if has_8conn and not has_4conn:
